// Claude AI Generated Todo App - Day 3
// Simple in-memory todo list application with basic CRUD operations
// Generated by Claude Haiku 4.5 as part of 100 Days of Code challenge

class TodoApp {
    constructor() {
          this.todos = [];
          this.nextId = 1;
    }

  // Add a new todo
  addTodo(title, description = '') {
        const todo = {
                id: this.nextId++,
                title,
                description,
                completed: false,
                createdAt: new Date(),
        };
        this.todos.push(todo);
        return todo;
  }

  // Get all todos
  getAllTodos() {
        return this.todos;
  }

  // Get todos by completion status
  getTodosByStatus(completed) {
        return this.todos.filter(todo => todo.completed === completed);
  }

  // Mark todo as complete
  completeTodo(id) {
        const todo = this.todos.find(t => t.id === id);
        if (todo) {
                todo.completed = true;
                todo.completedAt = new Date();
                return todo;
        }
        return null;
  }

  // Delete a todo
  deleteTodo(id) {
        const index = this.todos.findIndex(t => t.id === id);
        if (index > -1) {
                return this.todos.splice(index, 1)[0];
        }
        return null;
  }

  // Get stats
  getStats() {
        return {
                total: this.todos.length,
                completed: this.todos.filter(t => t.completed).length,
                pending: this.todos.filter(t => !t.completed).length,
        };
  }
}

// Example usage
const app = new TodoApp();
app.addTodo('Learn JavaScript', 'Master ES6+ features');
app.addTodo('Build a project', 'Create a real-world application');
app.addTodo('Review code', 'Understand design patterns');

console.log('All Todos:', app.getAllTodos());
console.log('Stats:', app.getStats());
